import {
  ArcElement,
  BarController,
  BarElement,
  CategoryScale,
  Chart,
  DoughnutController,
  Filler,
  Legend,
  LinearScale,
  LineController,
  LineElement,
  PieController,
  PointElement,
  ScatterController,
  TimeScale,
  Tooltip,
} from 'chart.js';

let registered = false;

export function registerChartJs(): void {
  if (registered) return;
  Chart.register(
    LineController,
    LineElement,
    PointElement,
    BarController,
    BarElement,
    PieController,
    DoughnutController,
    ScatterController,
    ArcElement,
    LinearScale,
    TimeScale,
    CategoryScale,
    Tooltip,
    Legend,
    Filler,
  );
  registered = true;
}
